const crypto = require('crypto');

const payload = $node.Webhook.json.payload || {};
const secret = String(process.env.OPS_WEBHOOK_HMAC_SECRET || '').trim();

const raw_body = JSON.stringify(payload ?? {});

if (!secret) {
  throw new Error('WF09 config error: OPS_WEBHOOK_HMAC_SECRET is missing');
}

const signature = crypto
  .createHmac('sha256', secret)
  .update(raw_body)
  .digest('hex');

return {
  raw_body,
  signature,
  signature_header: 'x-ops-signature',
  endpoint: String(process.env.OPS_INGEST_ENDPOINT || 'https://nil-wealth-telegram-shell.onrender.com/ops/ingest').trim(),
  event_type: payload?.event_type || null,
  trace_id: payload?.trace_id || null,
  idempotency_key: payload?.idempotency_key || null,
  debug_preview: {
    raw_body_length: raw_body.length,
    signature,
  },
};

return {
  ok: true,
  forwarded_at: new Date().toISOString(),
  event_type: $node['Generate HMAC Signature'].json.event_type,
  trace_id: $node['Generate HMAC Signature'].json.trace_id,
  idempotency_key: $node['Generate HMAC Signature'].json.idempotency_key,
  signature: $node['Generate HMAC Signature'].json.signature,
  raw_body_length: $node['Generate HMAC Signature'].json.debug_preview.raw_body_length,
};
